INSERT INTO `cpl` VALUES ('07f8df87-4ba6-45b5-86d8-7c9a69be8c9b','37ae7117-971d-41e0-a2ae-e41e7b99dbab','CPL04','Mampu membuat perencanaan infrastruktur TI, arsitektur jaringan, layanan fisik dan cloud, menganalisa konsep identifikasi, otentikasi, otorisasi akses dalam konteks melindungi orang dan perangkat',NULL,'2026-06-13 11:52:21.522','2026-06-13 11:52:21.522'),('0887486c-0cd1-4b67-93b9-c02ff8045db1','37ae7117-971d-41e0-a2ae-e41e7b99dbab','CPL11','Mampu menunjukkan sikap taat hukum, disiplin, dan menghargai keanekaragaman melalui internalisasi nilai, norma, etika akademik, semangat kemandirian, kejuangan, dan kewirausahaan',NULL,'2026-06-13 11:52:21.542','2026-06-13 11:52:21.542'),('0d59247e-b861-4919-8138-40c36d4cd04d','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL14','Mampu melakukan evaluasi diri dan supervisi terhadap penyelesaian pekerjaan sebagai wujud tanggung jawab atas pencapaian hasil kelompok kerja',NULL,'2026-06-13 09:44:30.914','2026-06-13 09:44:30.914'),('278abfce-b6d0-4dba-92ff-4006bb6dd514','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL10','Mampu menunjukkan sikap profesionalitas, integritas, dan berjati diri islami yang dilengkapi dengan kemampuan komunikasi, kepemimpinan, bekerja sama dan bertanggung jawab atas pekerjaan di bidang keahliannya, bermasyarakat, berbangsa, dan bernegara sebagai warga negara yang bangga dan cinta tanah air berlandaskan nilai ahlus sunah waljamahah',NULL,'2026-06-13 09:44:30.906','2026-06-13 09:44:30.906'),('3e103e33-5b4b-4725-82cc-1f809dab5776','37ae7117-971d-41e0-a2ae-e41e7b99dbab','CPL01','Mampu memahami, menganalisis, dan menilai konsep dasar dan peran sistem informasi dalam mengelola data dan memberikan rekomendasi pengambilan keputusan pada proses dan sistem organisasi.',NULL,'2026-06-13 11:52:21.509','2026-06-13 11:52:21.509'),('3e2ed74a-d55c-4128-938f-60d40fbccf09','37ae7117-971d-41e0-a2ae-e41e7b99dbab','CPL10','Mampu menunjukkan sikap profesionalitas, integritas, dan berjati diri islami yang dilengkapi dengan kemampuan komunikasi, kepemimpinan, bekerja sama dan bertanggung jawab atas pekerjaan di bidang keahliannya',NULL,'2026-06-13 11:52:21.540','2026-06-13 11:52:21.540'),('42e2cab0-8717-452c-97d1-e24d86173e91','37ae7117-971d-41e0-a2ae-e41e7b99dbab','CPL09','Mampu memahami dan menerapkan model sistem, metode dan berbagai teknik peningkatan bisnis proses, peluang inovasi digital dalam pengelolaan bisnis bidang kesehatan yang memanfaatkan teknologi',NULL,'2026-06-13 11:52:21.537','2026-06-13 11:52:21.537'),('5282e9b3-2def-4475-b973-ba9a6de59dc5','37ae7117-971d-41e0-a2ae-e41e7b99dbab','CPL14','Mampu melakukan evaluasi diri dan supervisi terhadap penyelesaian pekerjaan sebagai wujud tanggung jawab atas pencapaian hasil kelompok kerja',NULL,'2026-06-13 11:52:21.550','2026-06-13 11:52:21.550'),('6271e975-ce2e-4675-abb5-81af09804320','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL08','Mampu memahami dan menerapkan konsep, metode, teknik, dan tahapan data mining serta visualisasi data dalam pengolahan data, pengorganisasian data, dan penyajian informasi yang efektif, efisien, dan estetik',NULL,'2026-06-13 09:44:30.902','2026-06-13 09:44:30.902'),('657aa661-df63-4f5f-8611-d86c7b63c45a','37ae7117-971d-41e0-a2ae-e41e7b99dbab','CPL13','Mampu mengkaji implikasi pengembangan ilmu pengetahuan dengan menerapkan keahliannya dalam rangka menghasilkan solusi, menyusun deskripsi saintifik hasil kajian dalam bentuk laporan ilmiah yang sahih dan original',NULL,'2026-06-13 11:52:21.547','2026-06-13 11:52:21.547'),('72622c7f-aace-498d-a532-9049de4da49a','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL05','Mampu memahami dan menerapkan kode etik dalam penggunaan informasi dan data pada perancangan, implementasi, dan penggunaan suatu sistem',NULL,'2026-06-13 09:44:30.896','2026-06-13 09:44:30.896'),('72f1b54d-10ce-4a8d-b60a-4aed8cea7b45','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL06','Memiliki kemampuan merencanakan, menerapkan, memelihara dan meningkatkan sistem informasi organisasi untuk mencapai tujuan dan sasaran organisasi yang strategis baik jangka pendek maupun jangka panjang.',NULL,'2026-06-13 09:44:30.898','2026-06-13 09:44:30.898'),('826fb91d-808a-4e72-8060-071b2b1c3dfe','37ae7117-971d-41e0-a2ae-e41e7b99dbab','CPL03','Mampu memahami dan menggunakan berbagai metodologi pengembangan sistem beserta alat pemodelan sistem dan menganalisa kebutuhan pengguna dalam membangun sistem informasi untuk mencapai tujuan organisasi',NULL,'2026-06-13 11:52:21.518','2026-06-13 11:52:21.518'),('8e036740-fd5d-4896-bf94-c726ba590ea1','37ae7117-971d-41e0-a2ae-e41e7b99dbab','CPL07','Mampu memahami, mengidentifikasi dan menerapkan konsep, teknik dan metodologi manajemen proyek sistem informasi.',NULL,'2026-06-13 11:52:21.531','2026-06-13 11:52:21.531'),('90403176-06aa-40c5-92b8-20709b229e6e','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL09','Mampu memahami dan menerapkan model sistem, metode dan berbagai teknik peningkatan bisnis proses, peluang inovasi digital dalam pengelolaan bisnis bidang kesehatan yang memanfaatkan teknologi',NULL,'2026-06-13 09:44:30.904','2026-06-13 09:44:30.904'),('9511959b-14d6-4b13-98b1-e4ef9eb970c2','37ae7117-971d-41e0-a2ae-e41e7b99dbab','CPL02','Mampu merancang dan menggunakan database, serta mengolah dan menganalisa data dengan alat dan teknik pengolahan data',NULL,'2026-06-13 11:52:21.514','2026-06-13 11:52:21.514'),('a9560b1b-6554-4b9c-bdb0-99e7a85be676','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL04','Mampu membuat perencanaan infrastruktur TI, arsitektur jaringan, layanan fisik dan cloud, menganalisa konsep identifikasi, otentikasi, otorisasi akses dalam konteks melindungi orang dan perangkat',NULL,'2026-06-13 09:44:30.894','2026-06-13 09:44:30.894'),('ada956cd-5190-4dae-84ad-f5ff95ef927e','2fe0f250-d0fe-4a8d-a961-9f67a3abe722','CPL11','Mampu menunjukkan sikap taat hukum, disiplin, dan menghargai keanekaragaman melalui internalisasi nilai, norma, etika akademik, semangat kemandirian, kejuangan, dan kewirausahaan',NULL,'2026-06-13 09:44:30.909','2026-06-